package com.chaobo.scm.supplier.application.score;
import com.chaobo.scm.common.error.*;import java.math.*;import java.util.*;
public final class SupplierScoringDomainService{private SupplierScoringDomainService(){}public static Result calculate(List<Rule> rules,List<Fact> facts,BigDecimal adjustment){if(rules==null||rules.isEmpty())throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"评分周期内没有已发布规则");BigDecimal weight=rules.stream().map(Rule::weight).reduce(BigDecimal.ZERO,BigDecimal::add);if(weight.compareTo(BigDecimal.ONE)!=0)throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"评分规则权重之和必须为1");Map<String,BigDecimal> dimensions=new LinkedHashMap<>();for(var r:rules){var values=facts.stream().filter(f->f.metricCode().equals(r.metricCode())).map(Fact::value).toList();BigDecimal actual=values.isEmpty()?BigDecimal.ZERO:values.stream().reduce(BigDecimal.ZERO,BigDecimal::add).divide(BigDecimal.valueOf(values.size()),6,RoundingMode.HALF_UP);BigDecimal ratio=r.direction()==1?actual.divide(r.target(),6,RoundingMode.HALF_UP):r.target().divide(actual.signum()==0?BigDecimal.valueOf(0.000001):actual,6,RoundingMode.HALF_UP);BigDecimal score=ratio.min(BigDecimal.ONE).multiply(BigDecimal.valueOf(100)).multiply(r.weight());dimensions.merge(r.dimensionCode(),score,BigDecimal::add);}BigDecimal total=dimensions.values().stream().reduce(BigDecimal.ZERO,BigDecimal::add).add(adjustment==null?BigDecimal.ZERO:adjustment).max(BigDecimal.ZERO).min(BigDecimal.valueOf(100)).setScale(2,RoundingMode.HALF_UP);return new Result(total,dimensions);}public record Rule(String dimensionCode,String metricCode,BigDecimal weight,BigDecimal target,int direction){}public record Fact(String metricCode,BigDecimal value){}public record Result(BigDecimal total,Map<String,BigDecimal> dimensions){}}
